const secret = $input.first().headers['x-n8n-secret'];
if (secret !== $env.N8N_WEBHOOK_SECRET) throw new Error('Unauthorized');
return $input.all();

const task  = $('Fetch Task').first().json[0];
const event = $('Validate Secret').first().json.body.event;
if (!task || !task.assignee?.wa_number) return [];

const due     = task.deadline ? new Date(task.deadline).toLocaleDateString('en-IN', { day:'numeric', month:'short' }) : 'No deadline';
const prio    = (task.priority || 'medium').toUpperCase();
const creator = task.creator?.full_name ?? 'Admin';

let message = '';

if (event === 'task_assigned') {
  message = `📋 *New Task Assigned*\n\nHi ${task.assignee.full_name.split(' ')[0]}!\n\n*${task.title}*\n${task.description ? task.description + '\n' : ''}\n🚨 Priority: ${prio}\n🗓 Due: ${due}\n👤 Assigned by: ${creator}\n\nReply *my tasks* to view all your tasks.`;
} else if (event === 'task_completed') {
  message = `✅ Task marked as complete: *${task.title}*\n\nGreat work, ${task.assignee.full_name.split(' ')[0]}! 🎉`;
} else if (event === 'task_overdue') {
  message = `⚠️ *Overdue Task*\n\n📋 *${task.title}* was due *${due}*.\n\nPlease update the status or contact your manager.`;
}

if (!message) return [];
return [{ json: { to: task.assignee.wa_number, message } }];
